import{_ as a,o as d,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const e="/media/202309//1693904775.0638502.png",l="/media/202309//1693904775.075794.png",s="/media/202309//1693904775.080359.png",n="/media/202309//1693904775.1202416.png",p="/media/202309//1693904775.1388495.png",o="/media/202309//1693904775.1435633.png",h="/media/202309//1693904775.1630986.png",c="/media/202309//1693904775.167212.png",_="/media/202411/2024-11-21_175750_4933040.21462302467886696.png",g="/media/202412/2024-12-17_103843_8114410.7318005693452063.png",u="/media/202412/2024-12-17_111330_7281750.7374590356767292.png",U=JSON.parse('{"title":"RK3328 评估板使用手册","description":"","frontmatter":{"title":"RK3328 评估板使用手册"},"headers":[],"relativePath":"hardware/rk3328-evb/manual.md","filePath":"hardware/rk3328-evb/manual.md","lastUpdated":null}'),m={name:"hardware/rk3328-evb/manual.md"};function b(I,t,x,k,f,P){return d(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="目-录" tabindex="-1">目 录 <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;目 录&quot;">​</a></h1><ol><li>编写目的</li><li>准备工作</li><li>接口描述</li><li>接口连接指南</li><li>使用方法 5.1 使用板载功放 5.2 使用外置功放</li><li>快速体验指南</li><li>替换唤醒词</li><li>发音人和音频替换</li><li>语义场景说明</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3328评估板开发资料（产品白皮书、规格书、使用手册），可以点击下载: <a href="/media/attachment/2026/01/RK3328%E8%AF%84%E4%BC%B0%E6%9D%BF%E4%BA%A7%E5%93%81%E8%B5%84%E6%96%99.zip">【附件】RK3328评估板产品资料.zip</a></p><h1 id="_1-编写目的" tabindex="-1">1.编写目的 <a class="header-anchor" href="#_1-编写目的" aria-label="Permalink to &quot;1.编写目的&quot;">​</a></h1><p>本文档旨在让用户快速体验RK3328 AIUI评估板开发套件语音交互开发套件。</p><h1 id="_2-准备工作" tabindex="-1">2.准备工作 <a class="header-anchor" href="#_2-准备工作" aria-label="Permalink to &quot;2.准备工作&quot;">​</a></h1><ul><li>RK3328 语音交互开发套件</li><li>Micro USB 数据线</li><li>电脑（操作系统 windows10，用于查看调试信息和客制化）</li></ul><h1 id="_3-接口描述" tabindex="-1">3.接口描述 <a class="header-anchor" href="#_3-接口描述" aria-label="Permalink to &quot;3.接口描述&quot;">​</a></h1><p><img src="'+e+'" alt="" title="null"></p><p>图 1 RK3328 AIUI评估板开发套件主板接口图</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>1</td><td>网口</td><td>连接网线，百M网口</td></tr><tr><td>2</td><td>HDMI</td><td>连接电视输出</td></tr><tr><td>3</td><td>复位按键</td><td>刷机按键</td></tr><tr><td>4</td><td>USB接口</td><td>USB Host口</td></tr><tr><td>5</td><td>USB接口</td><td>USB OTG口（刷机时需外接电源）</td></tr><tr><td>6</td><td>电源</td><td>DC12V 2A， DC5.5-2.1</td></tr><tr><td>7</td><td>电源座子</td><td>电源插头 PH2.54-2pin</td></tr><tr><td>8</td><td>喇叭</td><td>10W 4Ω 扬声器接口， PH2.54 4pin</td></tr><tr><td>9</td><td>耳机口</td><td>左右声道立体声输出</td></tr><tr><td>10</td><td>I2S</td><td>GPIO口复用I2S</td></tr><tr><td>11</td><td>MIC口</td><td>4/6 麦麦克风阵列接口</td></tr><tr><td>12</td><td>红外</td><td>红外控制</td></tr><tr><td>13</td><td>I2C</td><td>驱动灯板</td></tr><tr><td>14</td><td>UART1</td><td>TTL3.3V 波特率：由应用指定，H2.0-4P</td></tr><tr><td>15</td><td>UART2</td><td>TTL3.3V 波特率：1500000， PH2.0-4P</td></tr></tbody></table><p>表 1 RK3328 AIUI评估板开发套件接口说明</p><h1 id="_4-接口连接指南" tabindex="-1">4.接口连接指南 <a class="header-anchor" href="#_4-接口连接指南" aria-label="Permalink to &quot;4.接口连接指南&quot;">​</a></h1><p><strong>4.1将麦克风阵列连接至 RK3328 AIUI评估板开发套件</strong></p><p>麦克风阵列连线采用2*8-2.0 牛角排线，将插头按照缺口方向插入插座。</p><p><img src="'+l+'" alt="" title="null"></p><p>图 2 RK3328 AIUI评估板开发套件麦克风阵列接线图</p><p><strong>4.2将扬声器连接至RK3328 AIUI评估板开发套件</strong></p><p>扬声器接口采用 PH2.54-4P 座，将插头按照缺口方向插入插座。 如更换扬声器，请参照接口线序标识，L-代表左声道负极，L+代表左声道正极，R-代表右声道负极，R+代表右声道正极。如果采用外置功放，此接口不接。</p><p><img src="'+s+'" alt="" title="null"></p><p>图 3 RK3328片评估板开发套件扬声器接线图示</p><p><strong>4.3将TTL串口连接到上位机。</strong></p><p>TTL 串口采用 PH2.0-3P 插座， 将插头按照缺口方向插入插座。 为3.3VTTL 电平， 可采用USB 转 TTL 与上位机连接。 请参照 RK3328 评估板开发套件 的 TTL 串口接口线序标识， TX为数据发送， RX为数据接收， GND为供地。</p><p><img src="'+n+'" alt="" title="null"></p><p>图 4 RK3328 AIUI评估板开发套件串口接线图示</p><p><strong>4.4将电源、HDMI线，连接到 RK3328 AIUI评估板开发套件</strong></p><p>电源接口采用 DC5.5-2.1 插座或 PH2.54-2P 插座， 将插头按照缺口方向插入插座。 电源电压为 DC12V， 使用板载功放时， 提供电流不低于 3A。不使用板载功放时，提供电流不低于1A，请参照 RK3328 评估板开发套件的电源接口线序标识， DC12V 为电源正， GND为电源负。</p><p>。</p><p><img src="'+p+'" alt="" title="null"></p><p>图 5 RK3328 AIUI评估板开发套件电源、HDMI接线图</p><h1 id="_5-使用方法" tabindex="-1">5.使用方法 <a class="header-anchor" href="#_5-使用方法" aria-label="Permalink to &quot;5.使用方法&quot;">​</a></h1><p>本章介绍两种使用方式，如果自带功放满足扬声器声音大小的需求，则使用板载功放。若板载功放无法满足需求，则可以使用外接功放。</p><h2 id="_5-1使用板载功放" tabindex="-1">5.1使用板载功放 <a class="header-anchor" href="#_5-1使用板载功放" aria-label="Permalink to &quot;5.1使用板载功放&quot;">​</a></h2><p>使用RK3328 AIUI评估板开发套件板载功放时，将2个≤10W 4欧喇叭连接到RK3328 AIUI评估板开发套件上，并将串口按照线序连接到客户控制板上。</p><p><img src="'+o+'" alt="" title="null"></p><p>图 6 RK3328 AIUI评估板开发套件板载功放接线图</p><p><img src="'+h+'" alt="" title="null"></p><p>图 8 采用板载功放框架图</p><h2 id="_5-2使用外置功放" tabindex="-1">5.2使用外置功放 <a class="header-anchor" href="#_5-2使用外置功放" aria-label="Permalink to &quot;5.2使用外置功放&quot;">​</a></h2><p>使用RK3328 AIUI评估板开发套件外置功放时，将外置功放的喇叭做为参考信号连接到RK3328 AIUI评估板开发套件扬声器接口上，并将串口按照线序连接到客户控制板上</p><p><img src="'+c+`" alt="C:sersjyu2esktop置功放.png外置功放" title="null"></p><p>图 7 采用外置功放框架图</p><h1 id="_6-快速体验指南" tabindex="-1">6.快速体验指南 <a class="header-anchor" href="#_6-快速体验指南" aria-label="Permalink to &quot;6.快速体验指南&quot;">​</a></h1><p><strong>第一步：将所有连线接按照第三、四章连接好，将HDMI连接到电视机，在PC机端打开sscom 串口工具。</strong></p><p>串口工具， 请在提供的工具包内查找。</p><p><strong>第二步：配置串口工具设置，并打开串口。</strong></p><p>选择识别出来的USB转TTL 串口号， 如果USB转TTL没有驱动， 请在提供的工具包内查找并安装。设置波特率：1500000；数据位8；奇偶校验：无；停止位：1 流控制： 无。</p><p><strong>第三步：RK3328 AIUI评估板开发套件接通电源，查看串口启动信息。</strong></p><p>接通电源后，大概1分钟左右，串口会收到启动信息。</p><p><strong>第四步： 体验语言唤醒、声源定位、噪声抑制、回声消除。</strong></p><ul><li><strong>唤醒:</strong></li></ul><p>启动评估板开发套件，当听到“叮”的一声提示音之后即可进行唤醒，默认唤醒词“小飞小飞”</p><ul><li><strong>交互</strong></li></ul><p>设备唤醒后支持持续的交互，用户可以连续的对话，并且在音频播放的过程中可打断，继续发出指令；</p><p>持续交互的过程中，支持说话人或其他人再次唤醒，再次唤醒将会清空之前</p><p>的音频和交互结果。</p><p>全双工交互过程中，识别引擎会对输入的无效语音和噪音进行过滤和拒识。</p><ul><li><strong>休眠</strong></li></ul><p>当 AIUI 发现超过 1 分钟（可设置）没有有效交互结果时，即会自动进入休眠状态。自动休眠时，正在播放的歌曲不会停止。喊出下方指令可以主动使 AIUI 进入休眠：跪安吧、退下吧、走开、安静会儿、休眠、关机、睡觉吧、 你去休息吧。</p><p>进入休眠后，唤醒时会清除上一轮的交互历史。</p><h1 id="_7-替换唤醒词" tabindex="-1">7.替换唤醒词 <a class="header-anchor" href="#_7-替换唤醒词" aria-label="Permalink to &quot;7.替换唤醒词&quot;">​</a></h1><p>RK3328评估板目前默认环形6麦算法集成的是AIUI平台最新优化唤醒响应时间的降噪算法，该版本唤醒词资源打包工具暂未上线平台，所以如需更换唤醒词可以联系讯飞线下支持获取（邮件发送 <a href="mailto:aiui_support@iflytek.com" target="_blank" rel="noreferrer">aiui_support@iflytek.com</a> 或联系讯飞商务同事申请获取），线下获取最新唤醒词资源后，查看资源文件，一般有三个文件：</p><ul><li>keyword.bin</li><li>mlp.bin</li><li>filler.irf</li></ul><p>主要需要使用 keyword.bin 资源，下面就替换流程做简单说明： 1、usb连接到PC端 2、使用adb命令操作，查看设备具体加载资源存放路径（默认环形6麦）</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shell</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sdcard/AIUI/assets/vtn/config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vtn_mic6_circle.ini</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+_+'" alt="" title="null"></p><p>3、在根据所在文件目录和名称直接重命名覆盖替换 建议：对原唤醒词资源文件进行备份，避免操作失误导致异常问题无法恢复。</p><h1 id="_8-发音人和音频替换" tabindex="-1">8.发音人和音频替换 <a class="header-anchor" href="#_8-发音人和音频替换" aria-label="Permalink to &quot;8.发音人和音频替换&quot;">​</a></h1><p>在3328评估板 /sdcard/ProductDemo/wav/ 文件夹下，保存了内置提示音频，具体说明如下： <img src="'+g+'" alt="" title="null"></p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>音频名称</strong></td><td><strong>内容</strong></td><td><strong>音频说明</strong></td></tr><tr><td>xxx_greeting_ss.wav</td><td>啥事</td><td>唤醒提示音频1</td></tr><tr><td>xxx_greeting_wz.wav</td><td>我在</td><td>唤醒提示音频2</td></tr><tr><td>xxx_greeting_zai.wav</td><td>在</td><td>唤醒提示音频3</td></tr><tr><td>xxx_greeting_zaine.wav</td><td>在呢</td><td>唤醒提示音频4</td></tr><tr><td>xxx_network_error.wav</td><td>网络有点问题，我去休息了，请稍后再试</td><td>网络异常提示音频</td></tr><tr><td>xxx_no_network.wav</td><td>网络未连接，请连接网络</td><td>网络未连接提示音频</td></tr><tr><td>xxx_wrong_appid.mp3</td><td>appid配置不成功，请先在手机端配置</td><td>appid配置提示音频</td></tr><tr><td>alarm.mp3</td><td>\\</td><td>闹钟提示音频</td></tr><tr><td>search_result.mp3</td><td>\\</td><td>查询提示音频</td></tr><tr><td>start_success.mp3</td><td>\\</td><td>开机和配网成功提示音频</td></tr><tr><td>tone_goodbye.mp3</td><td>\\</td><td>休眠提示音频</td></tr><tr><td>volume.wav</td><td>\\</td><td>音量操作提示音频</td></tr></tbody></table><h3 id="注意" tabindex="-1">注意： <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>音频文件名称中的 xxx 代表发音人名称，对应aiui.cfg中voice_name 取值。当发音人名称所在音频不存在时，默认加载 x4_lingxiaoying_em_v2 发音人对应的相关提示音频</p><p>修改方式： 1、本地按照音频内容制作相关音频文件，并根据需要替换的发音人名称重新命名，最后push到 /sdcard/ProductDemo/wav 目录下。 例如唤醒提示音频1，需要修改的发音人为：x_qige，则音频命名为 x_qige_greeting_ss.wav 2、从 /sdcard/AIUI/cfg 目录下pull 出 aiui.cfg，修改 TTS（语音合成）.voice_name 取值为需要的发音人名称，如 x_qige。 修改完成后push aiui.cfg到原目录下进行替换 <img src="'+u+'" alt="" title="null"></p><p>3、adb reboot 重启设备即可</p><h1 id="_9-语义场景说明" tabindex="-1">9.语义场景说明 <a class="header-anchor" href="#_9-语义场景说明" aria-label="Permalink to &quot;9.语义场景说明&quot;">​</a></h1><p>AIUI 默认场景包括天气、音乐、航班、火车、 诗词、智能家居，如果需要更多场景，请登录 <a href="http://www.xfyun.cn/services/aiui" target="_blank" rel="noreferrer">http://www.xfyun.cn/services/aiui</a> 进行配置</p>',77)])])}const q=a(m,[["render",b]]);export{U as __pageData,q as default};
